      columnCount,
      maxDateRangeFrom: clientSettings.data?.maxDateRangeFrom,
      // WARN: Do not remove: CAS-839
      // maxDateRangeTo: clientSettings.data?.maxDateRangeTo,
      maxDateRangeTo: dayjs().format("YYYY-MM-DD"),
      companyId,
    });

  const categoryFilterState = useCategoryFilter();
  const { categoryFilter, allCategoryValues } = categoryFilterState;

  const {
    data,
    isPending: isCashflowPending,
    isFetching,
    isPlaceholderData: isCashflowPlaceholder,
    error,
  } = useGetCashFlowAndBalanceStates({
    params: {
      dateFrom,
      dateTo,
      currency,
      bankAccountIdArray,
      sumAggregationIntervalGranularity: interval,
      category: mapCategoryFilterToParam(categoryFilter, allCategoryValues),
    },
  });

  // Cached data for the active key should render immediately. Only show loading
  // states when the active key has no cached payload yet and React Query is still
  // serving placeholder data from the previous selection.
  const isInitialLoading = clientSettings.isPending || isCashflowPending;
  const isFilterTransitionLoading =
    !isInitialLoading && isCashflowPlaceholder && isFetching;
  const isTableLoading = isInitialLoading || isFilterTransitionLoading;

  const selectedColumn = useMemo(
    () =>
      data?.cashFlowStates?.sumArray
        ? findColumnIndexForDate(
            data.cashFlowStates.sumArray,
            timePeriodControls.selectedDay,
          )
        : null,
    [data?.cashFlowStates?.sumArray, timePeriodControls.selectedDay],
  );

  if (error) {
    return (
      <EmptyState
        title={tt("error.title")}
        subtitle={error.message || tt("error.generic")}
        icon={<IconAlertCircle />}
      />
    );
  }

  if (
    !(isInitialLoading || isFilterTransitionLoading) &&
    (!data || (data.cashFlowStates?.sumArray?.length ?? 0) === 0)
  ) {
    return (
      <EmptyState
        icon={<IconBarChart03 />}
        title={tt("chart.noData")}
        subtitle={tt("chart.noDataDescription")}
      />
    );
  }

  return (
    <Stack sx={{ gap: 2 }}>
      <SelectionProvider selectedColumn={selectedColumn}>
        <TimePeriodProvider timePeriodControls={timePeriodControls}>
          {/* Upper Section - Health Indicators + Chart */}
          <Box
            sx={{
              display: "grid",
              gridTemplateColumns: {
                xs: "1fr",
                md: `${cashflowLayoutConfig.labelColumnWidth - cashflowLayoutConfig.yAxisWidth}px 1fr`,
              },
            }}
          >
            <HealthIndicatorsSection />
            <CashflowChartProvider
              data={data}
              interval={interval}
              setInterval={setInterval}
              currency={currency}
              bankAccountCount={bankAccountIdArray.length}
            >
              <CurrentBalanceChartSection
                isInitialLoading={isInitialLoading}
                isRefetching={isFilterTransitionLoading}
              />
            </CashflowChartProvider>
          </Box>

          {/* Bottom Section - Table */}
          <Box ref={tableContainerRef}>
            <CashflowTableProvider
              data={data}
              interval={interval}
              currency={currency}
              bankAccountIdArray={bankAccountIdArray}
              categoryFilterState={categoryFilterState}
            >
              <CashflowTableSection isLoading={isTableLoading} />
            </CashflowTableProvider>
          </Box>
        </TimePeriodProvider>
      </SelectionProvider>
    </Stack>
  );
}

import { useEffect, useMemo, useRef, useState } from "react";

import { cashflowLayoutConfig } from "../cashflow-layout.config.ts";

const MIN_COLUMNS = 3;
const MAX_COLUMNS = 14;
const DEFAULT_COLUMNS = 7; // Fallback for initial render before measurement

export type UseCashflowLayoutConfigResult = {
  /** Reference to attach to the table container element */
  tableContainerRef: React.RefObject<HTMLDivElement>;
  /** Number of columns that fit in the current container width */
  columnCount: number;
};

/**
 * Hook for managing cashflow table layout measurements.
 *
 * Handles:
 * - Container width observation via ResizeObserver
 * - Column count calculation based on available width
 * - Responsive adjustment within min/max bounds
 */
export function useCashflowLayoutConfig(): UseCashflowLayoutConfigResult {
  // Reference to table container to calculate number of columns to fit the screen
  const tableContainerRef = useRef<HTMLDivElement>(null);

  const [containerWidth, setContainerWidth] = useState<number | null>(null);

  // Observe container width changes
  useEffect(() => {
    if (!tableContainerRef?.current) return;

    const resizeObserver = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setContainerWidth(entry.contentRect.width);
      }
    });

    resizeObserver.observe(tableContainerRef.current);

    return () => {
      resizeObserver.disconnect();
    };
  }, [tableContainerRef]);

  // Calculate column count from container width and config
  const columnCount = useMemo(() => {
    if (containerWidth === null) {
      return DEFAULT_COLUMNS;
    }

    const { labelColumnWidth, dataColumnWidth } = cashflowLayoutConfig;
    const availableWidth = containerWidth - labelColumnWidth;
    const calculatedColumns = Math.floor(availableWidth / dataColumnWidth);

    return Math.max(MIN_COLUMNS, Math.min(MAX_COLUMNS, calculatedColumns));
  }, [containerWidth]);

  return {
    tableContainerRef,
    columnCount,
  };
}

